var e=JSON.parse(`[{"id":"L2_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"무슨 말을 하고 싶으신 겁니까?","JPN":"何をおっしゃりたいのですか？","ENG":"What are you trying to suggest?","TWN":"您是什麼意思？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_HATE"},"R":null}}},{"id":"L3_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"염동력이라면 지금도 계속 사용하고 있습니다.","JPN":"念動力でしたら、今でも使い続けています。","ENG":"I'm using my telekinesis right now.","TWN":"您說念動力，我現在也正在使用啊？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 그게 자네 전력은 아니지.","JPN":"だが、それが君の全力ではあるまい。","ENG":"Yes, but not to your full potential.","TWN":"但那不是妳的全力吧。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"확실한 방법이 있는데도 사용하지 않는 이유가 뭔지 궁금하군.","JPN":"切り札を持っていながら使わない理由が気になるが？","ENG":"I'm curious why you're not using a more sure-fire solution.","TWN":"對於妳不使用這種實際方法的理由，我感到很好奇呢。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"무섭나?","JPN":"怖いのか？","ENG":"Does it scare you?","TWN":"害怕嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L10_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......질문의 의도를 잘 모르겠군요.","JPN":"……質問の意図がわかりません。","ENG":"I'm not sure I follow.","TWN":"……我不明白您問題的含意。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"전력으로 힘을 개방하다가 정신까지 그림자가 되어 버릴까 봐, 두려운가?","JPN":"力を全て開放することで、\\n精神までシャドウになってしまいそうで怖いのか？","ENG":"Are you scared that even your mind will become a Shadow if you unleash your full power?","TWN":"全力釋放力量的話，會連意識都變成暗影，妳是在害怕這件事嗎？"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_SERIOUS2"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......그렇습니다.","JPN":"……おっしゃるとおりです。","ENG":"Yes... I am.","TWN":"……是的。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L15_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"완전히 그림자가 되어 버리면...... 지금 가진 기억들 전부를 잃어 버릴지도 모릅니다.","JPN":"完全にシャドウになってしまったら……\\n今までの記憶を全て失くしてしまうかもしれません。","ENG":"If I completely become a Shadow... I may lose all my memories.","TWN":"如果我完全變成暗影……可能會失去我所有的記憶。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"대원들의 격려도, 먼저 보낸 전우들의 모습도......","JPN":"隊員たちからの激励も、先に逝った戦友たちの姿も……","ENG":"About my troops cheering me on down there... and my comrades who already fell...","TWN":"隊員們的鼓勵，先走一步的戰友……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"제게는...... 하나하나가 모두 소중한데도 말입니다.","JPN":"私には……その一つ一つがすべてかけがえのないものです。","ENG":"To me... each and every one of them are so precious.","TWN":"對我來講……全都是珍貴的記憶。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"그걸 잃어 버린다는 건...... 제겐 죽음보다 더한 고통입니다.","JPN":"それを失くすということは……私にとっては死よりも重い苦痛です。","ENG":"To lose that... is to suffer a fate worse than death.","TWN":"失去那些記憶……比我死了還要痛苦。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"......자네도 꽤나 욕심쟁이로군.","JPN":"……君もずいぶんと欲張りだな。","ENG":"I guess even you can be greedy at times.","TWN":"……妳可真是貪心啊。"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L24_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"하지만 전대장, 내 개인적인 경험에 비추어 말하건데......","JPN":"だが戦隊長、私の個人的な経験から言わせてもらうが……","ENG":"But based on my personal experience, Commander...","TWN":"不過啊，隊長，以我個人的經驗來講……"},"stage":{"bg":"SPRING_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L25_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"지키고 싶은 게 있을 때는 주저하지 말게.","JPN":"何かを守りたいときは躊躇するな。","ENG":"It's best not to hesitate if there's someone you wish to protect.","TWN":"如果妳想要守護的事物，那就不要猶豫。"},"stage":{"bg":"SPRING_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L26_1","type":"dialog","speaker":"USER_ADMIN_NULL_NULL","text":{"KOREA":"머뭇거리다가 더욱 소중한 것을 잃어 버리게 되면 그때는 후회해도 늦었으니까.","JPN":"迷っていたせいでより大事なものを失くしてしまったら、\\n後で後悔しても遅いからな。","ENG":"If you lose that special someone while hesitating, it will be too late for regret by then.","TWN":"如果妳的猶豫讓妳失去更重要的東西，到時候後悔也來不及了。"},"stage":{"bg":"SPRING_01","slots":{"L":null,"C":null,"R":null}}},{"id":"L30_1","type":"dialog","speaker":"ARTIL_ADMIN_NULL_NULL","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SKY_RED","slots":{"L":null,"C":{"char_id":"ARTIL_ADMIN_NULL_NULL","face":"UNIT_DESPAIR"},"R":null}}}]`);export{e as default};